"""
MKT Context Commentary — Job chapter 42
Run: python3 scripts/zc-context-job-42-42.py

The resolution chapter: Job's response (vv1-6), divine verdict (vv7-9), restoration (vv10-17).
Key contextual frames:
- vv1-6: The distinction between second-hand theology and theophanic encounter (hearing vs. seeing)
- v6: The most disputed verse — what Job repents of; the ʾem-ʾas ambiguity
- vv7-9: God vindicates Job over the Friends — the book's theological reversal
- vv10-17: šûḇ šᵉḇûṯ (restoration-from-captivity) idiom; kiplāyim (doubling); patriarchal death formula
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "42": {
    "1": "<p>Job&#8217;s final speech to God. The book&#8217;s dialogue structure has moved through three cycles of debate (chs 3&#8211;31), Elihu&#8217;s four speeches (chs 32&#8211;37), the divine speeches from the whirlwind (chs 38&#8211;41), Job&#8217;s first brief response (40:3&#8211;5), a second divine speech (40:6&#8211;41:34), and now this final response. The arc from Job&#8217;s opening curse of his birth-day (ch3) to this closing submission before the Creator is the book&#8217;s spiritual trajectory. What has changed is not Job&#8217;s circumstances (still in ash-heap at this point) but his encounter with the living God.</p>",
    "2": "<p>&#8220;I know now that you can do all things and that no plan of yours can be stopped.&#8221; <em>Yāḏaʿtî kî-kōl tûkal</em> (I know that you can do all things) &#8212; the knowledge-claim is crucial. Job&#8217;s speeches throughout the dialogue have operated with considerable theoretical knowledge about God&#8217;s power (9:2&#8211;12 is a sustained argument that God is overwhelmingly powerful). What has changed is not the content of the claim but the mode of knowing: theoretical knowledge has become encountered knowledge. <em>Wᵉlōʾ-yibbāṣēr mimmᵉḵā mᵉzimmāh</em> (no purpose of yours can be thwarted) &#8212; <em>mᵉzimmāh</em> (purpose, plan, device) is confirmed as unstoppable. The implication: Job&#8217;s suffering was within God&#8217;s unstoppable purpose, not a deviation from it.</p>",
    "3": "<p>&#8220;You asked: &#8216;Who is this who speaks without knowledge?&#8217; Therefore I have spoken of things I did not understand &#8212; things too wonderful for me that I did not know.&#8221; Job quotes back the whirlwind&#8217;s opening challenge (38:2: &#8220;Who is this who darkens counsel by words without knowledge?&#8221;) and accepts it. The acceptance is epistemological rather than moral: <em>lāḵēn higgadtî wᵉlōʾ ʾāḇîn</em> (I have declared things I did not understand). The things too wonderful (<em>niplāʾôṯ mimmennî</em>) for Job&#8217;s comprehension are what the whirlwind speeches displayed: the governance of cosmic systems, the nature of created beings, the scope of divine knowledge. Job is not confessing sin but acknowledging the limits of creaturely comprehension.</p>",
    "4": "<p>&#8220;You said: &#8216;Listen, and I will speak; I will question you, and you shall answer me.&#8217;&#8221; Job quotes the whirlwind&#8217;s second invitation (38:3; 40:7): the divine invitation to dialogue, not to submission. The God who speaks from the whirlwind does not silence Job with mere power but engages him in dialogue &#8212; the very format Job longed for throughout the dialogue (9:32&#8211;35; 13:22; 31:35&#8211;37). The whirlwind speeches are in the genre of wisdom instruction-by-questioning: God does not answer Job&#8217;s specific questions but enlarges Job&#8217;s frame of reference through questions. Job now places himself within that frame.</p>",
    "5": "<p>&#8220;I had heard about you by report, but now my own eyes have seen you.&#8221; The pivot verse of the entire book. <em>Lᵉšēmaʿ-ʾōzen šᵉmaʿtîḵā</em> (I had heard of you by hearing of the ear) versus <em>wᵉʿattāh ʿênî rᵉʾāṯeḵā</em> (but now my own eye has seen you). The <em>šēmaʿ</em>/<em>rāʾāh</em> (hearing/seeing) contrast is fundamental to OT epistemology: seeing is the direct encounter that transforms; hearing alone produces tradition-received knowledge (what the Friends had in abundance). The Friends knew all the right things about God; Job has now seen God. This is not a claim to vision of the divine form (the whirlwind conceals as much as it reveals) but to the personal encounter that transforms the one who experiences it. The entire preceding dialogue was the process that made this encounter possible.</p>",
    "6": "<p>&#8220;Therefore I take back my words and repent in dust and ashes.&#8221; The most interpretively contested verse in the book. <em>ʾal-kēn ʾem-ʾas</em> &#8212; <em>ʾem-ʾas</em> can mean &#8220;I reject/despise&#8221; (with or without an object) or &#8220;I melt/dissolve.&#8221; The unstated object is debated: (1) &#8220;I despise myself&#8221; (traditional reading &#8212; Job abases himself completely); (2) &#8220;I retract my words&#8221; (MKT reading); (3) &#8220;I repudiate [my prior claim]&#8221; without specifying guilt. <em>Wᵉniḥamtî ʿal-ʿāpār wāʾēper</em> &#8212; <em>niḥam</em> (to repent, to be comforted, to change one&#8217;s mind) and the <em>ʿal</em> preposition (regarding/concerning) leave open whether Job is repenting in dust-and-ashes or repenting of/about/from his dust-and-ashes condition. God&#8217;s immediate vindication of Job (v7: Job spoke rightly) suggests the repentance is not of Job&#8217;s speech-content but of his forensic posture &#8212; the attempt to force God into a legal contest that Job&#8217;s encounter has rendered unnecessary.</p>",
    "7": "<p>&#8220;After the LORD had finished speaking with Job, he said to Eliphaz the Temanite: My anger burns against you and your two friends, because you have not spoken the truth about me, as my servant Job has.&#8221; The divine verdict that the book has been building toward. God&#8217;s <em>ḥārāh-ʾappî</em> (my anger burns) against Eliphaz and the Friends mirrors the prologue&#8217;s framing of Satan&#8217;s test: God&#8217;s honor is involved in whether Job&#8217;s fidelity is vindicated. <em>Lōʾ dibbartêm ʾēlay nᵉḵônāh</em> (you have not spoken to/about me what is right/established) &#8212; the Friends&#8217; speeches, despite their traditional piety and theological sophistication, failed the criterion of truth-about-God. Job&#8217;s speeches &#8212; including the accusations, the demands, the protest &#8212; were more truthful. The book&#8217;s counter-intuitive conclusion: honest anguished protest before God is truer piety than comfortable doctrinal correctness about God. Note that this does not mean Job&#8217;s theology was correct in all its claims; it means his relational honesty was more fitting than the Friends&#8217; relational performance.</p>",
    "8": "<p>&#8220;Now take seven bulls and seven rams, go to my servant Job, and offer a burnt offering for yourselves. My servant Job will pray for you, and I will accept his prayer on your behalf.&#8221; The sacral restoration procedure: seven bulls and seven rams &#8212; the number seven denoting completeness; the same animal combination appears in Num 23:1&#8211;4 (Balaam&#8217;s sacrifices) and Job 1:5 (Job&#8217;s sacrifices for his children). But the most dramatic element is the reversal of roles: Job, who has needed an intercessor throughout the dialogue (9:33; 16:19&#8211;21; 33:23), now becomes the intercessor. The one who was prostrate and accused becomes the priestly mediator for his accusers. <em>Kî ʾim-pānāyw ʾeśśā</em> (for I will lift up his face &#8212; accept him) &#8212; the idiom for granting a petition its full weight. Job&#8217;s intercessory prayer is accepted by God; the Friends&#8217; prayers for themselves would not have been.</p>",
    "9": "<p>&#8220;Eliphaz the Temanite, Bildad the Shuhite, and Zophar the Naamathite went and did what the LORD told them to do, and the LORD accepted Job&#8217;s prayer.&#8221; The obedience and acceptance are recorded without comment. Note that Elihu &#8212; who spoke at length in chs 32&#8211;37 &#8212; is not mentioned in the restoration narrative at all: not condemned with the Friends, not vindicated, simply absent from the epilogue. This silence has generated extensive interpretive discussion: does Elihu&#8217;s absence mean his speeches were approved (he needed no sacrifice), irrelevant, or that the chapter existed before Elihu&#8217;s speeches were added? The narrative&#8217;s silence is probably deliberate ambiguity. The acceptance of Job&#8217;s prayer closes the legal case: whatever charges stood against Job in the heavenly court, they are now vacated through the priestly intercession.</p>",
    "10": "<p>&#8220;The LORD restored Job&#8217;s fortunes after he prayed for his friends; the LORD doubled everything Job had previously.&#8221; <em>Wayᵉhāpēk YHWH ʾeṯ-šᵉḇûṯ ʾiyyôḇ</em> (the LORD turned the captivity/restoration of Job) &#8212; <em>šûḇ šᵉḇûṯ</em> is a fixed idiom in the OT for the restoration that follows exile: Jer 29:14; 30:3,18; Ezek 16:53; Hos 6:11; Amos 9:14; Zeph 2:7; Ps 126:4. Job&#8217;s suffering has been interpreted implicitly as an exile-condition; his restoration is the return from that exile. This gives the book a structural parallel with the exile-and-return narrative that Israel itself would later inhabit. The condition of the restoration is significant: it comes <em>bᵉhitpallᵉlô bᵉʿaḏ rēʿêhû</em> (while he prayed for his friends) &#8212; the restoration is sequentially connected to the intercessory prayer, not to any prior action of Job&#8217;s own merit.</p>",
    "11": "<p>&#8220;Then all his brothers and sisters and everyone who had known him before came and ate a meal with him in his house.&#8221; The social restoration follows the material and precedes the narrative account of specific doubling. The community that had abandoned Job in his suffering (19:13&#8211;19: brothers, acquaintances, kinsmen, friends, servants, wife, children, young boys &#8212; all estranged) now returns. The covenant-meal (<em>wayyōʾḵᵉlû lāḥem ʿimmô ḇᵉḇêṯô</em>, they ate bread with him in his house) is the primary act of restored relationship in ancient Near Eastern social customs. The <em>nāḥam</em> (consolation) and <em>niḥam</em> (comfort) that the Friends failed to provide (&#8220;miserable comforters,&#8221; 16:2) are now properly offered. The silver and gold gifts are marks of restored honor &#8212; the reverse of the honor-stripping that Job&#8217;s suffering represented.</p>",
    "12": "<p>&#8220;The LORD blessed the latter part of Job&#8217;s life more than the former: fourteen thousand sheep, six thousand camels, a thousand teams of oxen, and a thousand female donkeys.&#8221; The precise doubling of the prologue&#8217;s inventory (1:3: seven thousand sheep, three thousand camels, five hundred yoke of oxen, five hundred female donkeys). Fourteen thousand = 2 &#215; 7,000; six thousand = 2 &#215; 3,000; one thousand teams = 2 &#215; 500; one thousand donkeys = 2 &#215; 500. The exactness of the doubling is a narrative signal: this is not accidental prosperity but calculated restoration, the <em>kiplāyim</em> (double) that Zophar threatened as punishment (11:6: &#8220;God exacts from you less than your guilt deserves&#8221;) now deployed as blessing. The word <em>ʾaḥᵃrîṯ</em> (the latter part) echoes 8:7 (Bildad: &#8220;your beginning will seem small, and your latter part will be very great&#8221;) &#8212; Bildad was accidentally right, but through a mechanism he did not understand.</p>",
    "13": "<p>&#8220;He also had seven sons and three daughters.&#8221; The children are replaced with exactly the same number (1:2: seven sons and three daughters). This raises an immediate question the narrative does not answer: why not double the children as the animals were doubled? Various explanations have been proposed: (1) the original children are not truly lost &#8212; they live in Sheol and are waiting; doubling would imply they are simply replaceable like livestock; (2) the OT generally does not present Sheol as a place from which the dead return, so this interpretation requires something beyond the OT frame; (3) the same number is itself the gift &#8212; new family of identical number, not identical individuals. The question the text raises without answering is part of its intentional incompleteness: some losses in this life are not accounted for within this life.</p>",
    "14": "<p>&#8220;He named the first Jemimah, the second Keziah, and the third Keren-happuch.&#8221; The daughter-names are laden with sensory beauty: <em>yᵉmîmāh</em> (Dove &#8212; or possibly &#8220;warm&#8221; from <em>yōm</em>, day), <em>qᵉṣîʿāh</em> (Cassia, a fragrant spice used in the anointing oil, Exod 30:24; Ps 45:8), <em>qeren-happûḵ</em> (Horn of Eye-cosmetic/Kohl &#8212; the eye-paint used by women for beautification). The naming of daughters with descriptive beauty-names is unusual in the OT genealogies, where daughters are frequently unnamed or unnamed beyond their function. The names are culturally resonant: dove (purity, beauty, peace), cassia (fragrant, priestly), eye-paint horn (beautification of vision). The significance is underscored by v15.</p>",
    "15": "<p>&#8220;In all the land no women were as beautiful as Job&#8217;s daughters, and their father gave them property alongside their brothers.&#8221; Two details without exact parallel in the restoration narratives: (1) the superlative beauty of the daughters in all the land &#8212; a patriarchal blessing-formula applied to daughters rather than sons (cf. the beauty of Sarah, Gen 12:14; Rachel, Gen 29:17; Abigail, 1 Sam 25:3; Tamar, 2 Sam 13:1; but those are narrative details, not formal inheritance-blessings); (2) the property inheritance alongside the sons. In the ancient Near East and in the OT law, daughters generally did not inherit alongside sons unless there were no sons (Num 27:1&#8211;11, the daughters of Zelophehad). Job gives his daughters inheritance &#8212; an extraordinary act of generosity that transcends normal patriarchal practice. This has been read as Job&#8217;s transformed understanding of his own creatureliness and his children&#8217;s equal worth before God.</p>",
    "16": "<p>&#8220;After all this, Job lived a hundred and forty years and saw his children and grandchildren to the fourth generation.&#8221; One hundred and forty years is exactly double the conventional patriarchal lifespan: 70 years was considered the full human lifespan (Ps 90:10). Job lives two full lifetimes after the restoration &#8212; a <em>kiplāyim</em> (doubling) even of his remaining years, though 140 is not explicitly stated as double his prior age. Seeing children to the fourth generation is the patriarchal blessing formula (Gen 50:23: Joseph saw Ephraim&#8217;s children to the third generation; Ps 128:6: seeing grandchildren). The fourth generation places Job at the deepest level of family continuity the OT imagination could express. The man who cursed his birth-day (ch3) now sees his life extend four generations beyond the restoration.</p>",
    "17": "<p>&#8220;So Job died, old and satisfied with life.&#8221; <em>Wayyāmāṯ ʾiyyôḇ zāqēn ûśᵉḇaʿ yāmîm</em> &#8212; the patriarchal death formula. <em>Śāḇēaʿ yāmîm</em> (satisfied/full of days) is used of Abraham (Gen 25:8: &#8220;full of years&#8221;), Isaac (Gen 35:29), David (1 Chr 29:28). This formula marks a death at the right time, with a life well-lived, having seen its proper fullness. Job is restored to the patriarchal pattern that his catastrophe seemed to have permanently shattered. The book ends not with philosophical resolution of the theodicy question (the question of innocent suffering is not &#8220;answered&#8221; in the sense of being logically explained) but with relational resolution: the God who addressed Job from the whirlwind is the God with whom Job dies satisfied. The ending is both backward-looking (restoration of what was lost) and anticipatory: the full satisfaction with life that Job finally experiences points beyond this life to the ultimate restoration that the resurrection promises.</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'job')
    merge_comm(existing, JOB)
    save_comm('mkt-context', 'job', existing)
    print('Job 42 mkt-context written.')

if __name__ == '__main__':
    main()
